#!/usr/bin/env node
/**
 * Categorize the i18n-leak-report by namespace prefix so content
 * cleanup can prioritize the highest-impact areas first. Reads
 * scripts/i18n-leak-report.json (generated by audit-en-leaks.mjs)
 * and groups each leak by the first dot-segment of its key.
 *
 * Why namespace? Because the impact of an EN-value leak depends on
 * where it shows: leaks in `hero.*` or `faq.*` or `nav.*` damage
 * SEO rankings on every locale URL. Leaks in `admin.*` or internal
 * dashboard surfaces don't affect SEO. The summary report lets us
 * pick the high-impact leaks first instead of trying to resolve
 * 1829 entries blindly.
 *
 * Usage:
 *   node scripts/i18n-leak-summary.mjs
 *   node scripts/i18n-leak-summary.mjs --locale=de
 *   node scripts/i18n-leak-summary.mjs --top=10
 */
import fs from "fs";
import path from "path";

const REPORT_PATH = "scripts/i18n-leak-report.json";
if (!fs.existsSync(REPORT_PATH)) {
  console.error(
    `Report missing at ${REPORT_PATH}. Run \`node scripts/audit-en-leaks.mjs\` first.`,
  );
  process.exit(2);
}

const args = process.argv.slice(2);
const localeArg = args.find((a) => a.startsWith("--locale="))?.split("=")[1];
const topArg = parseInt(args.find((a) => a.startsWith("--top="))?.split("=")[1] ?? "20", 10);

const report = JSON.parse(fs.readFileSync(REPORT_PATH, "utf-8"));

// Marketing-critical namespaces: leaks here tank SEO and need
// hand-authored translation, not Google Translate.
const HIGH_IMPACT = new Set([
  "hero",
  "topbar",
  "nav",
  "footer",
  "faq",
  "pricing",
  "predictions",
  "matchpredictions",
  "betTypes",
  "learn",
  "howItWorks",
  "trackrecord",
  "engine",
  "homepage",
  "ctas",
  "cta",
  "trust",
  "social",
  "social-proof",
  "newsletter",
  "subscribe",
  "subscriptions",
  "subscription",
  "comparison",
  "leagues",
  "about",
  "metadata",
  "bc",
]);

// Authoring-context namespaces (likely OK to leave as EN passthrough
// during MVP): dashboard surfaces, error states, admin tooling.
const LOW_IMPACT = new Set([
  "admin",
  "diagnostic",
  "diagnostics",
  "qa",
  "internal",
  "debug",
  "dev",
  "errors",
  "error",
  "loading",
]);

function categorize(key) {
  const ns = key.split(".")[0];
  if (HIGH_IMPACT.has(ns)) return { ns, impact: "HIGH" };
  if (LOW_IMPACT.has(ns)) return { ns, impact: "LOW" };
  return { ns, impact: "MEDIUM" };
}

const localeKeys = localeArg ? [localeArg] : Object.keys(report);

for (const loc of localeKeys) {
  const leaks = report[loc] ?? [];
  if (!leaks.length) continue;

  console.log(`\n──  ${loc.toUpperCase()}  (${leaks.length} leaks)  ──────────`);

  const byNs = new Map();
  const byImpact = { HIGH: 0, MEDIUM: 0, LOW: 0 };
  for (const leak of leaks) {
    const { ns, impact } = categorize(leak.key);
    byImpact[impact]++;
    if (!byNs.has(ns)) byNs.set(ns, { count: 0, impact, samples: [] });
    const e = byNs.get(ns);
    e.count++;
    if (e.samples.length < 3) e.samples.push(leak);
  }

  console.log(
    `  Impact: HIGH ${byImpact.HIGH}, MEDIUM ${byImpact.MEDIUM}, LOW ${byImpact.LOW}`,
  );

  const sorted = [...byNs.entries()].sort((a, b) => {
    if (a[1].impact !== b[1].impact) {
      const order = { HIGH: 0, MEDIUM: 1, LOW: 2 };
      return order[a[1].impact] - order[b[1].impact];
    }
    return b[1].count - a[1].count;
  });

  console.log(`  Top namespaces:`);
  for (const [ns, info] of sorted.slice(0, topArg)) {
    console.log(`    ${info.impact.padEnd(6)} ${ns.padEnd(22)} ${String(info.count).padStart(4)} leaks`);
    for (const sample of info.samples) {
      const trimmed = sample.value.length > 60 ? sample.value.slice(0, 57) + "…" : sample.value;
      console.log(`             • ${sample.key}: "${trimmed}"`);
    }
  }
}

// Cross-locale impact summary
console.log(`\n──  ROLL-UP ──────────────`);
const totalsByImpact = { HIGH: 0, MEDIUM: 0, LOW: 0 };
for (const leaks of Object.values(report)) {
  for (const leak of leaks) {
    totalsByImpact[categorize(leak.key).impact]++;
  }
}
console.log(`  HIGH-impact   leaks across all locales: ${totalsByImpact.HIGH}`);
console.log(`  MEDIUM-impact leaks across all locales: ${totalsByImpact.MEDIUM}`);
console.log(`  LOW-impact    leaks across all locales: ${totalsByImpact.LOW}`);
console.log(``);
console.log(
  `Prioritization: fix HIGH-impact leaks first (marketing surfaces`,
);
console.log(
  `that crawlers and visitors see). Use scripts/apply-i18n-batch.mjs`,
);
console.log(
  `with a hand-authored JSON to ship corrections in one shot per locale.`,
);
